SELECT id,code,name,permissions FROM merchant_role WHERE status=1 AND id IN
#{id}
ORDER BY id

SELECT id,merchant_id,account,name,phone,email,operator_type,shop_scope_type,status AS operator_status
FROM merchant_operator WHERE merchant_id=#{merchantId} AND operator_type=2 AND is_deleted=FALSE
ORDER BY id DESC LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(1)
FROM merchant_application ma
JOIN merchant m ON m.id = ma.merchant_id
WHERE m.region = #{region}
  AND m.is_deleted = FALSE

    AND ma.status = #{status}

